18	
19	    setMatches(mediaQueryList.matches);
20	    mediaQueryList.addEventListener("change", handleChange);
21	    return () => {
22	      mediaQueryList.removeEventListener("change", handleChange);
23	    };
24	  }, [query]);
25	
26	  return matches;
27	}
