183	export function getSlashModelOptions(
184	  provider: ProviderKind,
185	  customModels: readonly string[],
186	  query: string,
187	  selectedModel?: string | null,
188	): AppModelOption[] {
189	  const normalizedQuery = query.trim().toLowerCase();
190	  const options = getAppModelOptions(provider, customModels, selectedModel);
191	  if (!normalizedQuery) {
192	    return options;
193	  }
194	
195	  return options.filter((option) => {
196	    const searchSlug = option.slug.toLowerCase();
197	    const searchName = option.name.toLowerCase();
198	    return searchSlug.includes(normalizedQuery) || searchName.includes(normalizedQuery);
199	  });
200	}
