import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type AppTheme,
  type ThemeDefinition,
  BUILT_IN_THEMES,
  DEFAULT_THEME,
  isValidTheme,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:custom-theme";
const OLD_STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: { theme: AppTheme } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

// Migrate from old light/dark/system key to named theme, runs once at module load
(function runMigration() {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (isValidTheme(raw)) return;

  const oldRaw = localStorage.getItem(OLD_STORAGE_KEY);
  let migrated: AppTheme;
  if (oldRaw === "light") {
    migrated = "t3-light";
  } else if (oldRaw === "dark") {
    migrated = "t3-dark";
  } else {
    // "system" or absent — respect current system preference
    migrated = getSystemDark() ? "t3-dark" : "t3-light";
  }

  localStorage.setItem(STORAGE_KEY, migrated);
  if (oldRaw !== null) {
    localStorage.removeItem(OLD_STORAGE_KEY);
  }
})();

function getStored(): AppTheme {
  const raw = localStorage.getItem(STORAGE_KEY);
  return isValidTheme(raw) ? raw : DEFAULT_THEME;
}

function applyTheme(theme: AppTheme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const def = BUILT_IN_THEMES[theme];
  const root = document.documentElement;
  const { tokens, colorScheme } = def;

  root.style.setProperty("--background", tokens.background);
  root.style.setProperty("--foreground", tokens.foreground);
  root.style.setProperty("--primary", tokens.primary);
  root.style.setProperty("--primary-foreground", tokens.primaryForeground);
  root.style.setProperty("--t3-sidebar", tokens.sidebar);
  root.style.setProperty("--t3-sidebar-foreground", tokens.sidebarForeground);
  root.style.setProperty("--t3-editor", tokens.editor);
  root.style.setProperty("--t3-editor-foreground", tokens.editorForeground);
  root.style.setProperty("--t3-terminal", tokens.terminal);
  root.style.setProperty("--t3-terminal-foreground", tokens.terminalForeground);
  root.style.setProperty("--t3-status-bar", tokens.statusBar);
  root.style.setProperty("--t3-status-bar-foreground", tokens.statusBarForeground);

  root.classList.toggle("dark", colorScheme === "dark");

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): { theme: AppTheme } {
  const theme = getStored();

  if (lastSnapshot && lastSnapshot.theme === theme) {
    return lastSnapshot;
  }

  lastSnapshot = { theme };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;
  const themeDefinition: ThemeDefinition = BUILT_IN_THEMES[theme];
  const resolvedTheme: "light" | "dark" = themeDefinition.colorScheme;

  const setTheme = useCallback((next: AppTheme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme, themeDefinition } as const;
}

