import { APP_THEMES, BUILT_IN_THEMES, type ThemeColorTokens } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

function ThemeSwatch({ tokens }: { tokens: ThemeColorTokens }) {
  return (
    <div
      className="relative h-10 w-24 overflow-hidden rounded"
      style={{ background: tokens.editor }}
    >
      {/* Sidebar strip */}
      <div
        className="absolute inset-y-0 left-0 w-5"
        style={{ background: tokens.sidebar }}
      />
      {/* Fake content lines in the editor area */}
      <div className="absolute left-7 right-1 top-1.5 space-y-1">
        <div
          className="h-0.5 w-10 rounded-full opacity-40"
          style={{ background: tokens.editorForeground }}
        />
        <div
          className="h-0.5 w-7 rounded-full opacity-30"
          style={{ background: tokens.editorForeground }}
        />
        <div
          className="h-0.5 w-12 rounded-full opacity-25"
          style={{ background: tokens.editorForeground }}
        />
      </div>
      {/* Status bar strip */}
      <div
        className="absolute inset-x-0 bottom-0 h-2"
        style={{ background: tokens.statusBar }}
      />
    </div>
  );
}

export function ThemeSelector() {
  const { theme, setTheme } = useTheme();

  return (
    <div className="flex flex-wrap gap-3">
      {APP_THEMES.map((themeId) => {
        const def = BUILT_IN_THEMES[themeId];
        const selected = theme === themeId;
        return (
          <button
            key={themeId}
            type="button"
            onClick={() => setTheme(themeId)}
            className={`flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
              selected
                ? "border-primary/60 bg-primary/8"
                : "border-border bg-background hover:bg-accent"
            }`}
            aria-pressed={selected}
            aria-label={`Select ${def.label} theme`}
          >
            <ThemeSwatch tokens={def.tokens} />
            <div className="flex items-center justify-between gap-2">
              <span
                className={`text-xs font-medium ${
                  selected ? "text-foreground" : "text-muted-foreground"
                }`}
              >
                {def.label}
              </span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

